<?php
namespace App\Services;use App\Models\Workspace;
class EnterpriseModeService{public function isSaaS():bool{return config('workproof.edition','saas')==='saas'&&$this->flag('workproof.saas_enabled');}public function isPrivate():bool{return config('workproof.edition')==='private';}public function isEnterprise():bool{return config('workproof.edition')==='enterprise';}public function billingEnabled():bool{return $this->flag('workproof.billing_enabled');}public function multiTenantEnabled():bool{return $this->flag('workproof.multi_tenant_enabled');}public function localAiEnabled():bool{return $this->flag('workproof.local_ai_enabled');}public function resolveDefaultWorkspace():?Workspace{return $this->multiTenantEnabled()?null:Workspace::query()->orderBy('id')->first();}private function flag(string $key):bool{return filter_var(config($key),FILTER_VALIDATE_BOOL);}}
